                const m = body.match(/`[^`]+\.(ts|tsx|js|py|go|rs)`|source:\s*\S+|[a-zA-Z0-9_-]+\/[a-zA-Z0-9_/.-]+\.(ts|tsx|js)/g);
                citations += m ? m.length : 0;
